const item = $input.first().json;
const body = item.body || item;
const changedFiles = body.changed_files || '';
const diff = (body.diff || '').substring(0, 12000);
return [{
  json: {
    pr_author: body.pr_author || 'unknown',
    pr_title: body.pr_title || 'no title',
    changed_files_list: changedFiles,
    diff_summary: diff,
    repo_full_name: body.repo || '',
    pr_number: body.pr_number || 0,
    head_sha: body.head_sha || '',
    pr_html_url: body.pr_html_url || body.build_url || ''
  }
}];

