    {
      "role": "user",
      "content": "PR by {{ $json.pr_author }}
Title: {{ $json.pr_title }}

Changed files:
{{ $json.changed_files_list }}

Diff:
{{ $json.diff_summary }}"
    }
  ]
}

parameters.jsCode:
const item = $input.first().json;
let aiText = '';
try { aiText = item.content[0].text; } catch(e) { aiText = '{"passed":false,"risk_level":"unknown","issues":[{"severity":"high","title":"AI error","detail":"Could not get AI response","file":"unknown"}],"summary":"AI response error"}'; }
aiText = aiText.replace(/```json\s*/g,'').replace(/```\s*/g,'').trim();
let result;
try { result = JSON.parse(aiText); } catch(e) { result = { passed: false, risk_level: 'unknown', issues: [{severity:'high', title:'Parse error', detail: aiText.substring(0,200), file:'unknown'}], summary: 'AI response parse error' }; }
const prData = $('Prepare diff for AI').first().json;
const passed = result.passed === true;
const today = new Date().toISOString().split('T')[0];
const issueLines = (result.issues || []).map(i => `- **[${(i.severity||'info').toUpperCase()}]** ${i.title} — \`${i.file}\`
  ${i.detail}`).join('
');
const passComment = `## AI Gate — PASSED :white_check_mark:

> Risk level: **${result.risk_level||'low'}**

${result.summary}

${issueLines ? '### Notes
'+issueLines : '_No issues found. Clean diff._'}

---
_Reviewed by AI gate (Jenkins + n8n + Claude) • ${today}_`;
const failComment = `## AI Gate — BLOCKED :no_entry:

> Risk level: **${result.risk_level||'high'}**

${result.summary}

### Issues found
${issueLines}

---
**This build has been blocked by the AI gate.**
Fix the issues above and push a new commit to re-trigger.

_Reviewed by AI gate (Jenkins + n8n + Claude) • ${today}_`;
return [{ json: { pr_number: prData.pr_number, repo_full_name: prData.repo_full_name, pr_author: prData.pr_author, pr_title: prData.pr_title, head_sha: prData.head_sha, pr_html_url: prData.pr_html_url, passed: passed, risk_level: result.risk_level || 'unknown', summary: result.summary || '', issues: result.issues || [], comment_body: passed ? passComment : failComment } }];

